data_whisker_fac=data_whisker(data_response==1,:);
data_whisker_sup=data_whisker(data_response==2,:);
data_whisker_NR=data_whisker(data_response==0,:);

for ii=1:size(data_whisker_fac,1)
    data_whisker_fac(ii,:)= data_whisker_fac(ii,:)-nanmean(data_whisker_fac(ii,500:750));
end

for ii=1:size(data_whisker_sup,1)
    data_whisker_sup(ii,:)= data_whisker_sup(ii,:)-nanmean(data_whisker_sup(ii,500:750));
end
for ii=1:size(data_whisker_NR,1)
    data_whisker_NR(ii,:)= data_whisker_NR(ii,:)-nanmean(data_whisker_NR(ii,500:750));
end

data_whisker_fac_avg = nanmean(data_whisker_fac); %Calculate population average
data_whisker_fac_sd = nanstd(data_whisker_fac); %Calculate population SD
data_whisker_fac_sem = nanstd(data_whisker_fac)/sqrt(size(data_whisker_fac,1)); %Calculate population SEM

data_whisker_sup_avg = nanmean(data_whisker_sup); %Calculate population average
data_whisker_sup_sd = nanstd(data_whisker_sup); %Calculate population SD
data_whisker_sup_sem = nanstd(data_whisker_sup)/sqrt(size(data_whisker_sup,1)); %Calculate population SEM

data_whisker_NR_avg = nanmean(data_whisker_NR); %Calculate population average
data_whisker_NR_sd = nanstd(data_whisker_NR); %Calculate population SD
data_whisker_NR_sem = nanstd(data_whisker_NR)/sqrt(size(data_whisker_NR,1)); %Calculate population SEM

