figure; hold on;
shadedErrorBar(linspace(-0.75,1.25,size(data_whisker_fac_avg,2)),data_whisker_fac_avg,data_whisker_fac_sem,'r');
shadedErrorBar(linspace(-0.75,1.25,size(data_whisker_sup_avg,2)),data_whisker_sup_avg,data_whisker_sup_sem,'b');
shadedErrorBar(linspace(-0.75,1.25,size(data_whisker_NR_avg,2)),data_whisker_NR_avg,data_whisker_NR_sem,'k');

