%% Calculate latency suppression cells
threshold = 0.1; % 10% of max
latency=[];
% Suppression cells

for ii=1:size(data_whisker_sup,1)
    idx = data_whisker_sup(ii,:);
    [idx_peak idx_peakloc] = nanmin(idx(750:1250));
    idx_threshold=idx(750:1250)<=(threshold*idx_peak);
    idx_threshold(idx_peakloc+1:end)=[];
    idx_threshold=idx_threshold+1;
    idx_logical = find(idx_threshold==1);
    try
        latency(ii,1) = idx_logical(end);
    catch
        latency(ii,1) = 0;
    end
    latency(ii,2) = latency(ii,1)/1000;

    figure; hold on;
    plot(linspace(-0.75,1.25,size(data_whisker_fac_avg,2)),idx,'k');
    line([latency(ii,2) latency(ii,2)],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'r','LineWidth',0.5);
    ii
    pause;
    close all;
end

